from nicegui import ui

CSS = r"""
@import url('https://fonts.googleapis.com/css2?family=DM+Mono:wght@400;500&family=Manrope:wght@400;500;600;700;800&display=swap');
:root{--bg:#06080d;--panel:#0d121b;--panel2:#111824;--panel3:#151e2c;--line:#1d2939;--line2:#2b3b50;--text:#f7f9fc;--muted:#8a98ab;--dim:#58677b;--violet:#8b7cff;--cyan:#46d8ff;--green:#45e5a6;--amber:#ffc96b;--red:#ff718b;--shadow:0 24px 70px rgba(0,0,0,.28)}
*{box-sizing:border-box}html,body{background:var(--bg)!important;color:var(--text);font-family:Manrope,Inter,system-ui,sans-serif}.q-layout{background:radial-gradient(1000px 520px at 72% -12%,rgba(91,83,220,.15),transparent 58%),radial-gradient(700px 500px at 16% 108%,rgba(33,181,215,.08),transparent 60%),#06080d}.q-page-container{min-height:100vh}
.cw-header{height:64px;background:rgba(7,9,14,.82)!important;backdrop-filter:blur(22px) saturate(140%);border-bottom:1px solid rgba(255,255,255,.06)}.cw-drawer{background:linear-gradient(180deg,#0a0e15,#070a0f)!important;border-right:1px solid rgba(255,255,255,.07)}.cw-content{max-width:1600px;margin:0 auto;padding:34px 42px 96px;width:100%}
.cw-brand{font-weight:800;letter-spacing:-.04em;font-size:15px}.cw-brand-sub{font-size:8px;letter-spacing:.16em;color:#56657a;font-weight:800}.cw-kicker{font-size:9px;letter-spacing:.2em;color:var(--cyan);font-weight:800;text-transform:uppercase}.cw-title{font-size:42px;line-height:1;font-weight:800;letter-spacing:-.065em;margin-top:7px}.cw-subtitle{font-size:13px;color:var(--muted);margin-top:10px;max-width:820px;line-height:1.6}.cw-page-head{padding:4px 0 25px;border-bottom:1px solid rgba(255,255,255,.065);margin-bottom:2px}
.cw-card{background:linear-gradient(145deg,rgba(17,24,36,.96),rgba(9,14,22,.98))!important;border:1px solid rgba(255,255,255,.075);border-radius:18px!important;box-shadow:0 18px 60px rgba(0,0,0,.16);overflow:hidden}.cw-card-interactive{transition:transform .18s ease,border-color .18s ease,box-shadow .18s ease}.cw-card-interactive:hover{transform:translateY(-2px);border-color:rgba(74,216,255,.2);box-shadow:0 24px 70px rgba(0,0,0,.24)}
.cw-metric{min-height:132px;padding:20px 21px;position:relative}.cw-metric:before{content:'';position:absolute;left:0;top:20px;bottom:20px;width:2px;background:linear-gradient(var(--cyan),var(--violet));border-radius:99px}.cw-metric-label{font-size:9px;color:#78879b;letter-spacing:.14em;font-weight:800;text-transform:uppercase}.cw-metric-value{font-size:36px;font-weight:800;letter-spacing:-.065em;margin-top:10px;line-height:1}.cw-metric-note{font-size:10px;color:#647389;margin-top:10px}.cw-section-title{font-size:15px;font-weight:750;letter-spacing:-.025em}.cw-section-sub{font-size:10px;color:#69798e;margin-top:4px}.cw-section-head{display:flex;align-items:end;justify-content:space-between;margin-top:8px}
.cw-status{display:inline-flex;align-items:center;gap:7px;font-size:8px;letter-spacing:.12em;font-weight:800;padding:6px 10px;border-radius:999px;border:1px solid #2a3749;background:#0d131c}.cw-status:before{content:'';width:6px;height:6px;border-radius:50%;background:currentColor;box-shadow:0 0 10px currentColor}.cw-good{color:#6debb4;border-color:rgba(66,230,164,.25);background:rgba(66,230,164,.07)}.cw-warn{color:#ffd28a;border-color:rgba(255,197,107,.25);background:rgba(255,197,107,.07)}.cw-bad{color:#ff91a3;border-color:rgba(255,113,139,.25);background:rgba(255,113,139,.07)}.cw-neutral{color:#a8b5c6}
.cw-nav-label{font-size:8px;color:#46556a;letter-spacing:.18em;font-weight:800;margin:20px 16px 7px}.cw-nav .q-item{min-height:42px;border-radius:10px;margin:2px 9px;color:#8998ac;padding:0 12px;transition:.16s ease}.cw-nav .q-item:hover{background:rgba(255,255,255,.04);color:#fff;transform:translateX(2px)}.cw-nav-active{background:linear-gradient(90deg,rgba(139,124,255,.18),rgba(74,216,255,.045))!important;color:#fff!important;border:1px solid rgba(139,124,255,.22);box-shadow:inset 2px 0 0 var(--violet)}
.cw-top-search .q-field__control{height:38px!important;min-height:38px!important;background:rgba(255,255,255,.035)!important}.cw-hero{position:relative;padding:28px 30px;background:linear-gradient(125deg,rgba(20,30,44,.98),rgba(9,14,21,.98))!important}.cw-hero:after{content:'';position:absolute;width:480px;height:260px;right:-170px;top:-160px;background:radial-gradient(circle,rgba(74,216,255,.14),transparent 65%);pointer-events:none}.cw-hero-title{font-size:21px;font-weight:780;letter-spacing:-.04em}.cw-hero-copy{font-size:12px;color:#8492a6;line-height:1.7;max-width:760px;margin-top:7px}
.cw-console{background:linear-gradient(180deg,#05080c,#070b10);border:1px solid #1b2938;border-radius:16px;padding:19px;font-family:'DM Mono',monospace;font-size:11px;line-height:1.7;color:#a9bad0;white-space:pre-wrap;max-height:520px;overflow:auto;box-shadow:inset 0 1px rgba(255,255,255,.025)}
.cw-stage-card{padding:24px 20px}.cw-stage-wrap{position:relative}.cw-stage-wrap:before{content:'';position:absolute;left:6%;right:6%;top:8px;height:1px;background:linear-gradient(90deg,#26374a,#536b8d,#26374a)}.cw-stage{position:relative;min-width:110px;text-align:center;z-index:1}.cw-orb{width:16px;height:16px;border-radius:50%;background:#455267;border:4px solid #0d131c;box-shadow:0 0 0 1px #334155;margin:auto}.cw-orb.good{background:var(--green);box-shadow:0 0 18px rgba(66,230,164,.5)}.cw-orb.run{background:var(--cyan);box-shadow:0 0 20px rgba(74,216,255,.6);animation:pulse 1.7s infinite}.cw-orb.bad{background:var(--red);box-shadow:0 0 18px rgba(255,113,139,.35)}@keyframes pulse{50%{box-shadow:0 0 30px rgba(74,216,255,.8)}}.cw-stage-name{font-size:10px;color:#c2ccda;margin-top:11px}.cw-stage-state{font-size:8px;color:#59677a;letter-spacing:.1em;margin-top:4px}
.cw-funnel-card{padding:22px}.cw-funnel-row{display:grid;grid-template-columns:110px minmax(100px,1fr) 56px;align-items:center;gap:14px;margin:15px 0}.cw-funnel-name{font-size:11px;color:#8997aa}.cw-funnel-value{text-align:right;font-size:11px;color:#e6edf7;font-weight:750}.cw-funnel-track{height:8px;background:#16212e;border-radius:99px;overflow:hidden}.cw-funnel-fill{height:100%;background:linear-gradient(90deg,var(--cyan),var(--violet));border-radius:99px;box-shadow:0 0 16px rgba(74,216,255,.2)}.cw-funnel-zero{width:3px!important;opacity:.35}
.cw-table .q-table__container{background:#090e15;border:1px solid rgba(255,255,255,.075);border-radius:16px;box-shadow:none;overflow:hidden}.cw-table thead tr{background:#101722}.cw-table th{font-size:8px!important;letter-spacing:.1em;text-transform:uppercase;color:#718096!important;font-weight:800!important;height:44px!important}.cw-table td{font-size:11px!important;color:#c8d2df;border-color:#151f2b!important;height:44px!important}.cw-table tbody tr:hover{background:rgba(139,124,255,.055)}
.cw-health-grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:14px}.cw-health{padding:18px 20px;min-height:112px}.cw-health-name{font-size:13px;font-weight:750;color:#e7edf6}.cw-health-detail{font-family:'DM Mono',monospace;font-size:10px;color:#66758a;margin-top:9px;overflow-wrap:anywhere}.cw-health-meta{font-size:9px;color:#59677a;letter-spacing:.09em;text-transform:uppercase;margin-top:10px}
.cw-callout{padding:16px 18px;border:1px solid rgba(255,197,107,.18);background:rgba(255,197,107,.045);border-radius:14px}.cw-callout-title{font-size:12px;font-weight:750;color:#f3d9a4}.cw-callout-copy{font-size:11px;color:#8f826e;margin-top:4px;line-height:1.5}.cw-toolbar{padding:12px 14px;background:rgba(14,20,30,.8);border:1px solid rgba(255,255,255,.07);border-radius:14px}
.q-btn{border-radius:10px;font-weight:700;letter-spacing:0;text-transform:none;min-height:40px}.q-btn.bg-primary{background:linear-gradient(135deg,#7168ef,#657ef6)!important;box-shadow:0 10px 28px rgba(105,101,240,.2)}.q-field--outlined .q-field__control:before{border-color:#263548}.q-field__control{background:#0c121a;border-radius:10px!important}.q-menu{background:#111722;color:#e7edf6;border:1px solid #273446}.q-tab{color:#74849a}.q-tab--active{color:#fff}.q-tab__indicator{background:linear-gradient(90deg,var(--violet),var(--cyan))!important}.cw-empty{padding:54px;text-align:center;color:#718096;border:1px dashed #29374a;border-radius:16px;background:rgba(255,255,255,.012)}
.cw-grid-5{display:grid;grid-template-columns:repeat(5,minmax(0,1fr));gap:14px}.cw-grid-4{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:14px}.cw-grid-3{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:14px}.cw-grid-2{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:18px}.cw-split{display:grid;grid-template-columns:minmax(0,1.55fr) minmax(320px,.65fr);gap:18px}.cw-command{font-size:9px;color:#66758a;border:1px solid #263548;background:#0c121a;padding:4px 7px;border-radius:6px;font-family:'DM Mono',monospace}
@media(max-width:1200px){.cw-grid-5{grid-template-columns:repeat(3,1fr)}.cw-grid-4{grid-template-columns:repeat(2,1fr)}.cw-grid-2,.cw-split,.cw-health-grid{grid-template-columns:1fr}.cw-content{padding:28px 24px 72px}}@media(max-width:680px){.cw-grid-5,.cw-grid-4,.cw-grid-3{grid-template-columns:1fr}.cw-title{font-size:34px}.cw-content{padding:22px 14px 60px}.cw-funnel-row{grid-template-columns:90px 1fr 44px}}
"""


def apply_theme() -> None:
    ui.colors(
        primary="#7b72f2",
        secondary="#4ad8ff",
        positive="#42e6a4",
        negative="#ff718b",
        warning="#ffc56b",
        dark="#06080d",
    )
    ui.add_css(CSS)
